{
  "title": "造梦日记",
  "url": "https://zmrj.art/",
  "functions": [
    {
      "name": "AI图像生成",
      "description": "基于AI算法，输入文字或图片即可生成高质量图片，支持中英文提示词输入。"
    },
    {
      "name": "多风格图像创作",
      "description": "支持油画、水彩、哑光画、儿童画、素描、中国风、电影感、摄影、动漫风、游戏场景、吉卜力、低聚艺术、像素艺术、CG渲染、赛博朋克、蒸汽波、虚幻引擎、印象主义、未来主义、超现实主义、浮世绘、室内设计等海量风格。"
    },
    {
      "name": "艺术大师风格模仿",
      "description": "可以模仿毕加索、梵高、莫奈、丰子恺、永井博、保罗·塞尚、托马斯·科尔、约翰·哈利斯、马克·西莫内蒂、托马斯·金凯德、西尔文·塞瑞尔等艺术大师的创作风格。"
    },
    {
      "name": "多尺寸支持",
      "description": "支持1:1、16:9、9:16、3:4、4:3等多种尺寸和分辨率的图像生成，可根据画面内容选择相应尺寸。"
    },
    {
      "name": "定制模型训练",
      "description": "用户可上传对应要求的图像后训练生成限定款图片或自推理生成图片，定制模型的训练时间约需30分钟。"
    }
  ],
  "roles": [
    {
      "name": "设计师",
      "description": "为平面设计师、插画师提供快速创意图像生成，支持商业设计和创意表达。"
    },
    {
      "name": "内容创作者",
      "description": "为自媒体、博主、作家提供配图和插画创作，丰富内容视觉表现。"
    },
    {
      "name": "艺术爱好者",
      "description": "为艺术爱好者提供创意表达平台，轻松创作各种风格的艺术作品。"
    }
  ],
  "features": [
    {
      "name": "西湖大学技术支持",
      "description": "由西湖大学深度学习实验室和西湖心辰（Friday AI 写作助手背后的团队）联合出品，技术实力雄厚。"
    },
    {
      "name": "超强算力支持",
      "description": "拥有超强算力支持，实现超快出图速度，提升用户体验。"
    },
    {
      "name": "多端支持",
      "description": "目前支持微信小程序和网页端等多个平台，使用便捷。"
    }
  ],
  "scenarios": [
    {
      "name": "创意设计场景",
      "description": "设计师可以通过输入创意描述快速生成多种风格的设计稿，比如输入'科技感十足的产品海报设计'，选择相应的风格和尺寸，即可获得多个设计方案，大大提升设计效率和创意灵感。"
    },
    {
      "name": "内容配图场景",
      "description": "自媒体运营者在撰写文章时，可以根据文章主题生成匹配的插图，比如写一篇关于春天的文章，输入'春天的樱花盛开，阳光明媚'等描述，选择合适的艺术风格，即可获得精美的配图。"
    },
    {
      "name": "个人创作场景",
      "description": "普通用户可以将自己的想象或梦境转化为视觉作品，比如输入一句诗词、歌词或者emoji表情，平台会根据这些输入生成对应的艺术图像，让抽象的想法变成具体的视觉表达。"
    }
  ],
  "pricing_plan": [
    {
      "name": "免费额度",
      "description": "新用户注册后可免费获得100颗造梦星，每日签到可领取一定数量的星星，用于兑换图片生成服务。"
    },
    {
      "name": "月卡会员 50元",
      "description": "每月50元，可以获得600颗造梦星，享受更快速度和更多尺寸的出图服务。"
    },
    {
      "name": "季卡会员 128元",
      "description": "3个月128元，可以获得2000颗造梦星，享受VIP专属服务和优先处理。"
    },
    {
      "name": "年卡会员 388元",
      "description": "12个月388元，可以获得8000颗造梦星，性价比最高的选择。"
    },
    {
      "name": "摘星套餐",
      "description": "按需购买造梦星：12元150颗、40元600颗、148元2500颗，适合偶尔使用的用户。"
    }
  ],
  "usage": [
    {
      "name": "网页端使用",
      "description": "用户首先访问造梦日记官网(https://zmrj.art/)，点击'开始创作'按钮进入生成页面。在页面中选择造梦画板或ControlNet画板，然后在文本框中描述想要生成的画面场景，可以是具体的物品描述、场景描述、诗句、歌词甚至emoji表情。接下来选择喜欢的艺术风格，如写真、流光、摄影、动漫风等，还可以上传参考图片。最后选择合适的图像尺寸和生成数量，点击生成按钮即可。整个过程简单直观，支持中英文输入，生成速度快。"
    },
    {
      "name": "微信小程序使用",
      "description": "用户可以在微信中搜索'造梦日记'小程序，打开后即可开始使用。小程序版本针对移动端进行了优化，界面简洁易用。使用流程与网页端类似：输入描述文字、选择风格、设置参数、生成图片。小程序的优势在于随时随地都能使用，无需下载安装，且与微信生态完美整合，生成的图片可以直接分享到微信朋友圈或发送给好友。对于经常使用手机的用户来说，小程序版本更加便捷实用。"
    },
    {
      "name": "定制模型训练",
      "description": "对于有特殊需求的用户，造梦日记提供定制模型训练功能。用户需要先准备一组符合要求的训练图片（通常需要10-20张同类型或同风格的图片），然后上传到平台进行模型训练。训练时间约为30分钟，训练完成后用户就拥有了专属的AI模型，可以生成特定风格或特定对象的图片。这个功能特别适合品牌方、设计师或有特殊创作需求的用户，可以生成符合品牌调性或个人风格的专属图像内容。"
    }
  ]
}

{
  "functions": [
    {
      "name": "国风AI绘画创作",
      "description": "核心功能，用户通过输入中文文字描述（咒语），即可由AI智能生成具有中式传统审美的国风艺术作品，如水墨画、插画、皮影戏等风格。"
    },
    {
      "name": "多样化风格模板",
      "description": "平台内置了丰富的国风艺术风格模板，如图案、刺绣、传统国画、现代插画等，用户可以一键选用，快速开启创作，降低使用门槛。"
    },
    {
      "name": "创作者社区",
      "description": "提供一个充满活力的艺术交流社区，用户可以分享自己的AI作品，与其他创作者交流心得、互相启发，并可将作品发布到更广阔的平台。"
    }
  ],
  "roles": [
    {
      "name": "艺术创作者",
      "description": "无论是专业插画师、艺术家还是业余爱好者，都可以利用奇域AI快速将脑海中的创意转化为具有中式美学的视觉艺术品。"
    },
    {
      "name": "设计师",
      "description": "设计师可以利用奇域AI生成的国风元素或插画，作为设计素材应用于广告、产品包装、UI界面等，丰富设计内容，提升独特性。"
    },
    {
      "name": "内容创作者",
      "description": "博客作者、视频博主等内容创作者可以使用平台生成的独特国风图片，作为文章配图或视频素材，增强内容的视觉吸引力。"
    }
  ],
  "features": [
    {
      "name": "专注中式审美",
      "description": "奇域AI的AI模型深植于中国传统文化，经过大量国风艺术品训练，旨在精准捕捉并再现书法、绘画、建筑等领域的中式美学特点。"
    },
    {
      "name": "灵活的图片比例",
      "description": "支持生成多种常见的图片比例，如3:4、16:9、1:1等，满足用户在不同应用场景（如手机壁纸、社交媒体帖子）下的创作需求。"
    },
    {
      "name": "个性化咒语创作",
      "description": "除了使用预设模板，平台也支持用户完全自定义提示词（咒语），给予创作者高度的自由度，以实现更个性化和多样化的艺术表达。"
    }
  ],
  "scenarios": [
    {
      "name": "创作水墨风格插画",
      "description": "用户在输入框描述“云雾缭绕的黄山奇松”，然后选择“水墨画”风格模板和16:9的图片比例，AI即可生成四张不同构图的水墨风格作品供用户挑选。"
    },
    {
      "name": "设计节日海报",
      "description": "为制作中秋节主题海报，设计师输入“嫦娥奔月，桂树，玉兔”，选用“现代插画”风格，生成一张具有节日氛围和现代美感的插画作为海报主视觉。"
    },
    {
      "name": "获取社交媒体配图",
      "description": "内容创作者在发布一首关于“江南”的古诗时，可以使用奇域AI生成一张“烟雨朦胧的江南古镇”图片作为配图，提升帖子的意境和吸引力。"
    }
  ],
  "pricing_plan": [
    {
      "name": "免费内测",
      "description": "目前产品处于免费内测阶段。新用户注册即送100额度，每日签到可再获100额度。生成低分辨率图片消耗1额度，高分辨率消耗5额度。"
    },
    {
      "name": "额度获取",
      "description": "除了注册和签到，用户还可以通过推荐好友（+200额度）或自己的作品被他人点亮（+50额度）等方式免费获取更多创作额度。"
    },
    {
      "name": "未来付费计划",
      "description": "官方未来可能会推出付费购买额度或订阅会员的计划，以提供更稳定和高级的服务，具体方案待公布。"
    }
  ],
  "usage": [
    {
      "name": "网页端使用",
      "description": "1. 访问奇域AI官网(qiyuai.net)并注册登录；2. 在页面底部的输入框内填写描述画面的提示词；3. 选择图片尺寸和艺术风格；4. 点击“生成”按钮等待AI创作；5. 在生成的作品中选择满意的进行下载或分享。"
    },
    {
      "name": "移动端使用",
      "description": "奇域AI也支持在微信小程序中使用，用户可以在微信中搜索“奇域AI”，操作流程与网页端基本一致，方便在手机上随时随地进行创作。"
    }
  ],
  "questions": [
    {
      "name": "奇域AI支持哪些具体的国风风格？",
      "description": "根据其介绍，奇域AI支持包括但不限于传统国画、水墨画、现代插画、刺绣、皮影戏、京剧等多种具有中国文化特色的艺术风格。"
    },
    {
      "name": "免费额度用完了怎么办？",
      "description": "您可以通过每日签到、推荐新用户或发布受欢迎的作品来持续免费获取额度。在当前的免费内测阶段，这些是主要的额度补充方式。"
    },
    {
      "name": "生成的图片可以用于商业用途吗？",
      "description": "关于商业使用的具体条款，建议查阅官网的用户协议或服务条款。通常在内测阶段，平台可能会对商业使用有所限制，或在未来推出专门的商业授权计划。"
    }
  ]
}
